// Score user access events against per-user baselines. The signal the SOC
// cares about is the COMBINATION: off-hours + unusual location + sensitive
// data access together is far more suspicious than any one alone.
const body = $json.body ?? $json;
const events = Array.isArray(body) ? body : (body.events ?? []);
if (events.length === 0) return [{ json: { no_events: true } }];

// --- Mock baselines. Real deployment: computed from 30-90 days of history. ---
const BASELINES = {
  'j.smith':    { usual_countries: ['TR'], usual_hours: [7, 19], role: 'Finance Analyst',   sensitive_normal: ['finance-reports'] },
  'a.yilmaz':   { usual_countries: ['TR'], usual_hours: [8, 18], role: 'HR Specialist',     sensitive_normal: ['hr-payroll-db'] },
  'c.demir':    { usual_countries: ['TR', 'DE'], usual_hours: [9, 21], role: 'Senior Engineer', sensitive_normal: ['source-code-repo'] },
  'svc-backup': { usual_countries: ['TR'], usual_hours: [0, 24], role: 'Service Account',   sensitive_normal: ['*'] },
};
const SENSITIVE_RESOURCES = ['hr-payroll-db', 'customer-pii-export', 'source-code-repo', 'finance-reports', 'board-documents'];
const BULK_BYTES = 500 * 1024 * 1024; // 500 MB

const byUser = {};
for (const e of events) {
  const u = e?.user ?? 'unknown';
  (byUser[u] = byUser[u] ?? []).push(e);
}

const results = [];
for (const [user, evts] of Object.entries(byUser)) {
  const base = BASELINES[user] ?? { usual_countries: [], usual_hours: [8, 18], role: 'unknown (no baseline)', sensitive_normal: [] };
  const signals = [];
  let score = 0;

  const offHours = evts.filter(e => {
    const h = new Date(e?.timestamp ?? Date.now()).getUTCHours();
    const day = new Date(e?.timestamp ?? Date.now()).getUTCDay();
    return h < base.usual_hours[0] || h >= base.usual_hours[1] || day === 0 || day === 6;
  });
  if (offHours.length > 0 && base.role !== 'Service Account') {
    score += 20;
    signals.push(`${offHours.length} event(s) outside usual hours ${base.usual_hours[0]}:00-${base.usual_hours[1]}:00`);
  }

  const newCountries = [...new Set(evts.map(e => e?.geo_country).filter(c => c && !base.usual_countries.includes(c)))];
  if (newCountries.length > 0) {
    score += 30;
    signals.push(`access from unusual location(s): ${newCountries.join(', ')} (baseline: ${base.usual_countries.join(', ') || 'none'})`);
  }

  const sensitiveHits = evts.filter(e => SENSITIVE_RESOURCES.includes(e?.resource) && !base.sensitive_normal.includes(e?.resource) && !base.sensitive_normal.includes('*'));
  if (sensitiveHits.length > 0) {
    score += 35;
    signals.push(`accessed sensitive resource(s) outside role: ${[...new Set(sensitiveHits.map(e => e.resource))].join(', ')}`);
  }

  const bytes = evts.reduce((s, e) => s + (Number(e?.bytes_transferred) || 0), 0);
  if (bytes > BULK_BYTES) {
    score += 15;
    signals.push(`bulk transfer: ${(bytes / 1024 / 1024).toFixed(0)} MB in window`);
  }

  // Combination bonus: three independent signal families together
  const signalFamilies = [offHours.length > 0, newCountries.length > 0, sensitiveHits.length > 0, bytes > BULK_BYTES].filter(Boolean).length;
  if (signalFamilies >= 3) {
    score += 10;
    signals.push('COMBINATION: 3+ independent anomaly families in one window');
  }

  if (score === 0) continue;
  results.push({
    json: {
      detection_id: `insider-${Date.now()}-${user}`,
      user,
      role: base.role,
      risk_score: Math.min(100, score),
      signals,
      signal_families: signalFamilies,
      event_count: evts.length,
      sample_events: evts.slice(0, 5),
      window_from: evts[0]?.timestamp ?? null,
      window_to: evts[evts.length - 1]?.timestamp ?? null,
    },
  });
}

if (results.length === 0) return [{ json: { no_events: false, no_anomalies: true } }];
return results;

// Malformed LLM output => escalate (conservative default for insider risk).
const det = $('Risk Band').item.json;
let out = $json.message?.content ?? $json.output ?? {};
if (typeof out === 'string') {
  try { out = JSON.parse((out.match(/\{[\s\S]*\}/) || ['{}'])[0]); } catch (e) { out = {}; }
}
const decision = ['escalate', 'watchlist'].includes(out.decision) ? out.decision : 'escalate';
// Strip Slack-active characters from LLM prose (injection defense).
const clean = s => String(s ?? '').replace(/[<>@]/g, '').slice(0, 600);
return { json: {
  ...det,
  llm_decision: decision,
  llm_confidence: Math.min(100, Math.max(0, Number(out.confidence) || 0)),
  llm_rationale: clean(out.rationale ?? 'LLM output failed validation (or the call failed) — escalating by default.'),
  verify_first: Array.isArray(out.benign_explanations_to_verify) ? out.benign_explanations_to_verify.map(clean) : [],
} };

