// Structured audit record (bounded) — production: audit table insert.
let ticket = null;
try { ticket = $('Jira: Confidential Insider-Risk Case').item.json?.key ?? null; } catch (e) {}
const sd = $getWorkflowStaticData('global');
const log = sd.audit_log ?? [];
log.push({
  ts: new Date().toISOString(),
  workflow: '10-insider-threat-detection',
  detection_id: $json.detection_id ?? null,
  user: $json.user ?? null,
  risk_score: $json.risk_score ?? null,
  outcome: $json.llm_decision ?? 'direct_escalation',
  ticket,
  delivery_ok: !$json.error,
  delivery_error: $json.error ? String($json.error.message ?? $json.error).slice(0, 200) : null,
});
if (log.length > 300) log.splice(0, log.length - 300);
sd.audit_log = log;
return { json: $json };
